/**
 * @suppress
 */
public object FfiConverterTypeStreamingWindowedFingerprinter: FfiConverter<StreamingWindowedFingerprinter, Pointer> {

    override fun lower(value: StreamingWindowedFingerprinter): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): StreamingWindowedFingerprinter {
        return StreamingWindowedFingerprinter(value)
    }

    override fun read(buf: ByteBuffer): StreamingWindowedFingerprinter {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: StreamingWindowedFingerprinter) = 8UL

    override fun write(value: StreamingWindowedFingerprinter, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



/**
 * A fingerprint result containing hash data and duration.
 */
data class FingerprintData (
    /**
     * Raw hash values.
     */
    var `hashes`: List<kotlin.UInt>, 
    /**
     * Duration of the audio in milliseconds.
     */
    var `durationMs`: kotlin.UInt
) {
    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeFingerprintData: FfiConverterRustBuffer<FingerprintData> {
    override fun read(buf: ByteBuffer): FingerprintData {
        return FingerprintData(
            FfiConverterSequenceUInt.read(buf),
            FfiConverterUInt.read(buf),
        )
    }

    override fun allocationSize(value: FingerprintData) = (
            FfiConverterSequenceUInt.allocationSize(value.`hashes`) +
            FfiConverterUInt.allocationSize(value.`durationMs`)
    )

    override fun write(value: FingerprintData, buf: ByteBuffer) {
            FfiConverterSequenceUInt.write(value.`hashes`, buf)
            FfiConverterUInt.write(value.`durationMs`, buf)
    }
}



