/**
 * A windowed fingerprint with timestamp information.
 */
data class WindowedFingerprint (
    /**
     * Timestamp in milliseconds from the start of the audio.
     */
    var `timestampMs`: kotlin.UInt, 
    /**
     * Duration of the fingerprinted segment in milliseconds.
     */
    var `durationMs`: kotlin.UInt, 
    /**
     * Raw hash values.
     */
    var `hashes`: List<kotlin.UInt>
) {
    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeWindowedFingerprint: FfiConverterRustBuffer<WindowedFingerprint> {
    override fun read(buf: ByteBuffer): WindowedFingerprint {
        return WindowedFingerprint(
            FfiConverterUInt.read(buf),
            FfiConverterUInt.read(buf),
            FfiConverterSequenceUInt.read(buf),
        )
    }

    override fun allocationSize(value: WindowedFingerprint) = (
            FfiConverterUInt.allocationSize(value.`timestampMs`) +
            FfiConverterUInt.allocationSize(value.`durationMs`) +
            FfiConverterSequenceUInt.allocationSize(value.`hashes`)
    )

    override fun write(value: WindowedFingerprint, buf: ByteBuffer) {
            FfiConverterUInt.write(value.`timestampMs`, buf)
            FfiConverterUInt.write(value.`durationMs`, buf)
            FfiConverterSequenceUInt.write(value.`hashes`, buf)
    }
}





/**
 * Error type for fingerprinting operations.
 */
sealed class FingerprintException: kotlin.Exception() {

    class DecodeException(

        val `msg`: kotlin.String
        ) : FingerprintException() {
        override val message
            get() = "message=${ `msg` }"
    }

    class UnsupportedFormat(

        val `msg`: kotlin.String
        ) : FingerprintException() {
        override val message
            get() = "message=${ `msg` }"
    }

    class InvalidInput(

        val `msg`: kotlin.String
        ) : FingerprintException() {
        override val message
            get() = "message=${ `msg` }"
    }

    class IoException(

        val `msg`: kotlin.String
        ) : FingerprintException() {
        override val message
            get() = "message=${ `msg` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<FingerprintException> {
        override fun lift(error_buf: RustBuffer.ByValue): FingerprintException = FfiConverterTypeFingerprintError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeFingerprintError : FfiConverterRustBuffer<FingerprintException> {
    override fun read(buf: ByteBuffer): FingerprintException {
        

        return when(buf.getInt()) {
            1 -> FingerprintException.DecodeException(
                FfiConverterString.read(buf),
                )
            2 -> FingerprintException.UnsupportedFormat(
                FfiConverterString.read(buf),
                )
            3 -> FingerprintException.InvalidInput(
                FfiConverterString.read(buf),
                )
            4 -> FingerprintException.IoException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FingerprintException): ULong {
        return when(value) {
            is FingerprintException.DecodeException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FingerprintException.UnsupportedFormat -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FingerprintException.InvalidInput -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is FingerprintException.IoException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
        }
    }

    override fun write(value: FingerprintException, buf: ByteBuffer) {
        when(value) {
            is FingerprintException.DecodeException -> {
                buf.putInt(1)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FingerprintException.UnsupportedFormat -> {
                buf.putInt(2)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FingerprintException.InvalidInput -> {
                buf.putInt(3)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is FingerprintException.IoException -> {
                buf.putInt(4)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalTypeFingerprintData: FfiConverterRustBuffer<FingerprintData?> {
    override fun read(buf: ByteBuffer): FingerprintData? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterTypeFingerprintData.read(buf)
    }

    override fun allocationSize(value: FingerprintData?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterTypeFingerprintData.allocationSize(value)
        }
    }

    override fun write(value: FingerprintData?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterTypeFingerprintData.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterSequenceShort: FfiConverterRustBuffer<List<kotlin.Short>> {
    override fun read(buf: ByteBuffer): List<kotlin.Short> {
        val len = buf.getInt()
        return List<kotlin.Short>(len) {
            FfiConverterShort.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.Short>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterShort.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.Short>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterShort.write(it, buf)
        }
    }
}




